### 3. After 코드 - 개선된 구현

**After 1: Entity에 인덱스 추가 + 필요 정보 포함**

```kotlin
// /domain/src/main/kotlin/com/maum/backend/entity/call/CallWaitingEntity.kt

@Entity
@Table(
    catalog = "maum",
    name = "call_waiting",
    indexes = [
        // 개선 1: status + createdAt 복합 인덱스 → 대기열 조회 full scan 제거
        Index(name = "idx_call_waiting_status_created", columnList = "status, created_at"),
        // 개선 2: userId 단일 인덱스 → 중복 대기 방지 쿼리 최적화
        Index(name = "idx_call_waiting_user_id", columnList = "user_id"),
    ]
)
class CallWaitingEntity(
    @Id
    val id: String = "",
    val userId: String,
    val status: String,
    // 개선 3: 매칭에 필요한 gender를 JOIN 없이 조회하기 위해 비정규화 저장
    val gender: String,
    val preferredGender: String,
    val matchedUserId: String? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

**After 2: fetch join + QueryDSL Projection으로 N+1 제거**

```kotlin
// /domain/src/main/kotlin/com/maum/backend/repository/call/CallWaitingRepository.kt

interface CallWaitingRepository : JpaRepository<CallWaitingEntity, String>, CallWaitingQueryRepository {

    // 개선: DB 레벨에서 필터링, 결과 1건만 반환
    @Query("""
        SELECT c FROM CallWaitingEntity c
        WHERE c.status = 'WAITING'
          AND c.userId != :excludeUserId
          AND c.gender = :targetGender
          AND c.preferredGender = :requestGender
        ORDER BY c.createdAt ASC
    """)
    fun findFirstCandidate(
        excludeUserId: String,
        targetGender: String,
        requestGender: String,
        pageable: Pageable,
    ): List<CallWaitingEntity>
}
```

```kotlin
// /domain/src/main/kotlin/com/maum/backend/repository/call/CallWaitingQueryRepository.kt

interface CallWaitingQueryRepository {
    fun findMatchCandidateProjection(
        excludeUserId: String,
        targetGender: String,
        requestGender: String,
    ): CallWaitingProjection?
}
```

```kotlin
// /domain/src/main/kotlin/com/maum/backend/repository/call/CallWaitingQueryRepositoryImpl.kt

@Repository
class CallWaitingQueryRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CallWaitingQueryRepository {

    // 개선: QueryDSL Projection으로 필요한 컬럼만 SELECT
    override fun findMatchCandidateProjection(
        excludeUserId: String,
        targetGender: String,
        requestGender: String,
    ): CallWaitingProjection? {
        val entity = QCallWaitingEntity.callWaitingEntity
        return queryFactory
            .select(
                Projections.constructor(
                    CallWaitingProjection::class.java,
                    entity.id,
                    entity.userId,
                )
            )
            .from(entity)
            .where(
                entity.status.eq("WAITING"),
                entity.userId.ne(excludeUserId),
                entity.gender.eq(targetGender),
                entity.preferredGender.eq(requestGender),
            )
            .orderBy(entity.createdAt.asc())
            .limit(1)
            .fetchOne()
    }
}

data class CallWaitingProjection(
    val waitingId: String,
    val userId: String,
)
```

**After 3: Redis 캐시 + 분산 락으로 매칭 중복 방지**

```kotlin
// /call/src/main/kotlin/com/maum/backend/call/service/CallMatchingService.kt

@Service
@Transactional
class CallMatchingService(
    private val callWaitingRepository: CallWaitingRepository,
    private val redisTemplate: StringRedisTemplate,
) {
    companion object {
        // TTL 설정
        private const val MATCH_STATUS_TTL_SECONDS = 30L    // 매칭 상태 캐시 30초
        private const val WAITING_QUEUE_TTL_SECONDS = 5L    // 대기열 캐시 5초
        private const val MATCH_LOCK_TTL_SECONDS = 3L       // 분산 락 3초

        // Redis Key 패턴
        private fun matchStatusKey(waitingId: String) = "call:match:status:$waitingId"
        private fun matchLockKey(userId: String) = "call:match:lock:$userId"
    }

    // 개선 1: Redis 분산 락으로 동시 매칭 중복 방지
    fun findAndMatch(requestUserId: String, waitingId: String, requestGender: String): MatchResult? {
        val lockKey = matchLockKey(requestUserId)
        val lockValue = UUID.randomUUID().toString()

        // SET NX EX 방식의 분산 락 획득
        val acquired = redisTemplate.opsForValue()
            .setIfAbsent(lockKey, lockValue, Duration.ofSeconds(MATCH_LOCK_TTL_SECONDS))

        if (acquired != true) {
            // 이미 다른 요청이 매칭 중
            return null
        }

        return try {
            val targetGender = if (requestGender == "MALE") "FEMALE" else "MALE"

            // 개선 2: QueryDSL Projection으로 단 1건, 필요한 컬럼만 조회
            val candidate = callWaitingRepository.findMatchCandidateProjection(
                excludeUserId = requestUserId,
                targetGender = targetGender,
                requestGender = requestGender,
            ) ?: return null

            // 개선 3: 매칭 상태를 Redis에 즉시 캐싱
            val statusKey = matchStatusKey(waitingId)
            redisTemplate.opsForValue().set(
                statusKey,
                candidate.userId,
                Duration.ofSeconds(MATCH_STATUS_TTL_SECONDS),
            )

            MatchResult(matchedUserId = candidate.userId, waitingId = waitingId)
        } finally {
            // 락 해제 (Lua 스크립트로 원자적 삭제)
            releaseLock(lockKey, lockValue)
        }
    }

    // 개선 4: 매칭 상태 확인을 DB가 아닌 Redis에서 조회 (DB 폴링 제거)
    fun checkMatchStatus(waitingId: String): MatchStatus {
        val statusKey = matchStatusKey(waitingId)
        val matchedUserId = redisTemplate.opsForValue().get(statusKey)

        return if (matchedUserId != null) {
            MatchStatus.MATCHED
        } else {
            // Redis 미스 시에만 DB 폴링 (fallback)
            val waiting = callWaitingRepository.findById(waitingId).orElse(null)
                ?: return MatchStatus.NOT_FOUND
            if (waiting.matchedUserId != null) MatchStatus.MATCHED else MatchStatus.WAITING
        }
    }

    // Lua 스크립트 기반 원자적 락 해제
    private fun releaseLock(lockKey: String, lockValue: String) {
        val script = """
            if redis.call('get', KEYS[1]) == ARGV[1] then
                return redis.call('del', KEYS[1])
            else
                return 0
            end
        """.trimIndent()
        redisTemplate.execute(
            RedisScript.of(script, Long::class.java),
            listOf(lockKey),
            lockValue,
        )
    }
}
```

**After 4: 대기열 입장 시 Redis Sorted Set으로 관리**

```kotlin
// /call/src/main/kotlin/com/maum/backend/call/service/CallWaitingQueueService.kt

@Service
class CallWaitingQueueService(
    private val redisTemplate: StringRedisTemplate,
) {
    companion object {
        // gender별 대기 큐: "call:waiting:queue:MALE", "call:waiting:queue:FEMALE"
        private fun waitingQueueKey(gender: String) = "call:waiting:queue:$gender"
        private const val QUEUE_TTL_SECONDS = 60L
    }

    // 개선 5: Redis Sorted Set으로 대기열 관리 (score = timestamp)
    // DB 없이 O(log N) 으로 대기열 조회 가능
    fun enqueue(userId: String, gender: String, waitingId: String) {
        val queueKey = waitingQueueKey(gender)
        val score = System.currentTimeMillis().toDouble()
        // value: "waitingId:userId" 형태로 저장
        redisTemplate.opsForZSet().add(queueKey, "$waitingId:$userId", score)
        redisTemplate.expire(queueKey, Duration.ofSeconds(QUEUE_TTL_SECONDS))
    }

    // 개선 6: 가장 오래 기다린 이성 후보를 Redis에서 O(1)에 가깝게 꺼냄
    fun dequeue(targetGender: String): Pair<String, String>? {
        val queueKey = waitingQueueKey(targetGender)
        // score 오름차순 첫 번째 원소 = 가장 오래 기다린 유저
        val entry = redisTemplate.opsForZSet().popMin(queueKey) ?: return null
        val parts = entry.value?.split(":") ?: return null
        if (parts.size < 2) return null
        return Pair(parts[0], parts[1]) // waitingId to userId
    }

    fun removeFromQueue(userId: String, gender: String) {
        // 매칭 취소 또는 만료 시 제거
        val queueKey = waitingQueueKey(gender)
        // ZSCAN으로 userId가 포함된 항목 제거
        redisTemplate.opsForZSet().scan(queueKey, ScanOptions.scanOptions().match("*:$userId").build())
            .use { cursor ->
                cursor.forEach { entry ->
                    redisTemplate.opsForZSet().remove(queueKey, entry.value)
                }
            }
    }
}
```

