**After 3: Redis 캐시 + 분산 락으로 매칭 중복 방지**

```kotlin
// /call/src/main/kotlin/com/maum/backend/call/service/CallMatchingService.kt

@Service
@Transactional
class CallMatchingService(
    private val callWaitingRepository: CallWaitingRepository,
    private val redisTemplate: StringRedisTemplate,
) {
    companion object {
        // TTL 설정
        private const val MATCH_STATUS_TTL_SECONDS = 30L    // 매칭 상태 캐시 30초
        private const val WAITING_QUEUE_TTL_SECONDS = 5L    // 대기열 캐시 5초
        private const val MATCH_LOCK_TTL_SECONDS = 3L       // 분산 락 3초

        // Redis Key 패턴
        private fun matchStatusKey(waitingId: String) = "call:match:status:$waitingId"
        private fun matchLockKey(userId: String) = "call:match:lock:$userId"
    }

    // 개선 1: Redis 분산 락으로 동시 매칭 중복 방지
    fun findAndMatch(requestUserId: String, waitingId: String, requestGender: String): MatchResult? {
        val lockKey = matchLockKey(requestUserId)
        val lockValue = UUID.randomUUID().toString()

        // SET NX EX 방식의 분산 락 획득
        val acquired = redisTemplate.opsForValue()
            .setIfAbsent(lockKey, lockValue, Duration.ofSeconds(MATCH_LOCK_TTL_SECONDS))

        if (acquired != true) {
            // 이미 다른 요청이 매칭 중
            return null
        }

        return try {
            val targetGender = if (requestGender == "MALE") "FEMALE" else "MALE"

            // 개선 2: QueryDSL Projection으로 단 1건, 필요한 컬럼만 조회
            val candidate = callWaitingRepository.findMatchCandidateProjection(
                excludeUserId = requestUserId,
                targetGender = targetGender,
                requestGender = requestGender,
            ) ?: return null

            // 개선 3: 매칭 상태를 Redis에 즉시 캐싱
            val statusKey = matchStatusKey(waitingId)
            redisTemplate.opsForValue().set(
                statusKey,
                candidate.userId,
                Duration.ofSeconds(MATCH_STATUS_TTL_SECONDS),
            )

            MatchResult(matchedUserId = candidate.userId, waitingId = waitingId)
        } finally {
            // 락 해제 (Lua 스크립트로 원자적 삭제)
            releaseLock(lockKey, lockValue)
        }
    }

    // 개선 4: 매칭 상태 확인을 DB가 아닌 Redis에서 조회 (DB 폴링 제거)
    fun checkMatchStatus(waitingId: String): MatchStatus {
        val statusKey = matchStatusKey(waitingId)
        val matchedUserId = redisTemplate.opsForValue().get(statusKey)

        return if (matchedUserId != null) {
            MatchStatus.MATCHED
        } else {
            // Redis 미스 시에만 DB 폴링 (fallback)
            val waiting = callWaitingRepository.findById(waitingId).orElse(null)
                ?: return MatchStatus.NOT_FOUND
            if (waiting.matchedUserId != null) MatchStatus.MATCHED else MatchStatus.WAITING
        }
    }

    // Lua 스크립트 기반 원자적 락 해제
    private fun releaseLock(lockKey: String, lockValue: String) {
        val script = """
            if redis.call('get', KEYS[1]) == ARGV[1] then
                return redis.call('del', KEYS[1])
            else
                return 0
            end
        """.trimIndent()
        redisTemplate.execute(
            RedisScript.of(script, Long::class.java),
            listOf(lockKey),
            lockValue,
        )
    }
}
